DROP TABLE IF EXISTS `disposisi`;

CREATE TABLE `disposisi` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `surat_masuk_id` bigint unsigned NOT NULL,
  `user_id` bigint unsigned NOT NULL,
  `diteruskan_kepada` json NOT NULL,
  `instruksi` enum('ACC/Setuju','Agar ditindaklanjuti','Buat resume','Koordinasikan','Sebagai Info','Laksanakan Sesuai Dengan Ketentuan','Lakukan Kajian','Menghadap','Monitor Perkembangannya','Pelajari/Ajukan Saran','Selesaikan','Simpan','Untuk Diketahui','Untuk Dilaksanakan','Copy') COLLATE utf8mb4_unicode_ci NOT NULL,
  `catatan` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `disposisi_surat_masuk_id_foreign` (`surat_masuk_id`),
  KEY `disposisi_user_id_foreign` (`user_id`),
  CONSTRAINT `disposisi_surat_masuk_id_foreign` FOREIGN KEY (`surat_masuk_id`) REFERENCES `surat_masuk` (`id`) ON DELETE CASCADE,
  CONSTRAINT `disposisi_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=29 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;




LOCK TABLES `disposisi` WRITE;

