DROP TABLE IF EXISTS `surat_keluar`;

CREATE TABLE `surat_keluar` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint unsigned DEFAULT NULL,
  `created_by_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tanggal_pembuatan` date DEFAULT NULL,
  `kategori_berkas` enum('berita acara','memo','mou','nota dinas','pemberitahuan','pengumuman','sppi/pendaftaran keluarga','surat dinas','surat edaran','surat gaji terusan','surat keterangan','surat kuasa','surat perintah','surat perintah perjalanan dinas','surat perjanjian kerja sama','surat pengantar','tinjau skep') COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tujuan` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `no_surat` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` enum('draft','proses','terkirim','selesai') COLLATE utf8mb4_unicode_ci DEFAULT 'draft',
  `no_resi` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `file_resi` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `perihal` text COLLATE utf8mb4_unicode_ci,
  `tingkat_urgensi_penyelesaian` enum('biasa','amat segera','segera') COLLATE utf8mb4_unicode_ci DEFAULT 'biasa',
  `klasifikasi_surat_dinas` enum('biasa','terbatas','rahasia','sangat rahasia') COLLATE utf8mb4_unicode_ci DEFAULT 'biasa',
  `keterangan` text COLLATE utf8mb4_unicode_ci,
  `file_path` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=7089 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



LOCK TABLES `surat_keluar` WRITE;

